            if (nextHostname == NULL) {
                break;
            }
        }
        printoutput(TRUE);
        BeaconPrintf(CALLBACK_OUTPUT, "[+] Finished enumerating!\n"); 

    } else {
        BeaconPrintf(CALLBACK_ERROR, "Couldn't load the host file from disk.\n");
    }

    return 0;
